// Parsear el input de Telegram
const input = ($input.all()[0] && $input.all()[0].json) || {};

let text = '';
let chatId = null;
let callbackQueryId = null;

if (input.message) {
  text = input.message.text || '';
  chatId = input.message.chat && input.message.chat.id;
} else if (input.callback_query) {
  text = input.callback_query.data || '';
  chatId = input.callback_query.message && input.callback_query.message.chat && input.callback_query.message.chat.id;
  callbackQueryId = input.callback_query.id;
}

const textRaw = String(text || '');
const textLower = textRaw.toLowerCase().trim();
let comando = 'desconocido';
const payload = {};

// ======================================================================
// HELPERS (timezone Argentina)
// ======================================================================
function fmtArgentina(d) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'America/Argentina/Buenos_Aires',
    year: 'numeric', month: '2-digit', day: '2-digit'
  }).formatToParts(d);
  const y = parts.find(p => p.type === 'year').value;
  const m = parts.find(p => p.type === 'month').value;
  const dd = parts.find(p => p.type === 'day').value;
  return `${y}-${m}-${dd}`;
}

function addDays(yyyy_mm_dd, n) {
  const [y, m, d] = yyyy_mm_dd.split('-').map(Number);
  const date = new Date(Date.UTC(y, m - 1, d));
  date.setUTCDate(date.getUTCDate() + n);
  const yy = date.getUTCFullYear();
  const mm = String(date.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(date.getUTCDate()).padStart(2, '0');
  return `${yy}-${mm}-${dd}`;
}

const hoyArgentina = () => fmtArgentina(new Date());

// ======================================================================
// STATIC DATA: leer contexto previo del orquestador
// ======================================================================
function loadContext() {
  try {
    if (!chatId) return;
    const staticData = $getWorkflowStaticData('global');
    const chatIdStr = String(chatId);
    const ctx = staticData['ctx_' + chatIdStr] || {};
    if (!payload.fecha && ctx.fecha) payload.fecha = ctx.fecha;
    if (!payload.rango && ctx.rango) payload.rango = ctx.rango;
  } catch (e) {}
}

function saveContext() {
  try {
    if (!chatId) return;
    const staticData = $getWorkflowStaticData('global');
    const chatIdStr = String(chatId);
    const existing = staticData['ctx_' + chatIdStr] || {};
    staticData['ctx_' + chatIdStr] = {
      fecha: payload.fecha || existing.fecha,
      rango: payload.rango || existing.rango
    };
  } catch (e) {}
}

// ======================================================================
// 1) Callbacks de botones inline
// ======================================================================
if (textRaw === 'cmd:crear' || textRaw.startsWith('cmd:crear:')) {
  comando = 'crear';
  if (textRaw.startsWith('cmd:crear:rango:')) {
    const rangoPart = textRaw.substring('cmd:crear:rango:'.length);
    payload.rango = rangoPart;
    if (rangoPart !== 'exacto') {
      let daysToAdd = 0;
      if (rangoPart === 'inmediato') daysToAdd = 1;
      else if (rangoPart === '2semanas') daysToAdd = 14;
      else if (rangoPart === '1mes') daysToAdd = 28;
      if (daysToAdd > 0) {
        payload.fecha = addDays(hoyArgentina(), daysToAdd);
        saveContext();
      }
    }
  } else if (textRaw.startsWith('cmd:crear:slot:')) {
    payload.slot = textRaw.substring('cmd:crear:slot:'.length);
    loadContext();
  } else if (textRaw.startsWith('cmd:crear:fecha:')) {
    payload.fecha = textRaw.substring('cmd:crear:fecha:'.length);
  }
} else if (textRaw === 'cmd:cancelar' || textRaw.startsWith('cmd:cancelar:')) {
  comando = 'cancelar';
  if (textRaw.startsWith('cmd:cancelar:turno_id:')) {
    payload.turno_id = textRaw.substring('cmd:cancelar:turno_id:'.length);
  }
} else if (textRaw === 'cmd:reprogramar' || textRaw.startsWith('cmd:reprogramar:')) {
  comando = 'reprogramar';
  if (textRaw.startsWith('cmd:reprogramar:turno_id:')) {
    payload.turno_id = textRaw.substring('cmd:reprogramar:turno_id:'.length);
  }
}
// ======================================================================
// 2) Input de hora HH:MM
// ======================================================================
else if (/^\d{1,2}:\d{2}$/.test(textRaw.trim())) {
  comando = 'crear';
  payload.slot = textRaw.trim();
  loadContext();
}
// ======================================================================
// 3) Input de número (slot_numero)
// ======================================================================
else if (/^\d+$/.test(textRaw.trim())) {
  const num = parseInt(textRaw.trim(), 10);
  if (num >= 1 && num <= 20) {
    comando = 'crear';
    payload.slot_numero = num;
    loadContext();
  }
}
// ======================================================================
// 4) Input de fecha DD/MM/AAAA
// ======================================================================
else if (/^(\d{2})\/(\d{2})\/(\d{4})$/.test(textRaw.trim())) {
  comando = 'crear';
  payload.fecha_raw = textRaw.trim();
}
// ======================================================================
// 5) Comandos de texto (slash + lenguaje natural)
// ======================================================================
else if (textLower.startsWith('/reservar') || textLower === 'reservar' || textLower.includes('quiero un turno') || textLower.includes('sacar turno') || textLower.startsWith('reservar:') || textLower.startsWith('reservar_lista_')) {
  comando = 'crear';
} else if (textLower.startsWith('/cancelar') || textLower === 'cancelar' || textLower.includes('dar de baja') || textLower.startsWith('cancelar:')) {
  comando = 'cancelar';
  if (textLower.startsWith('cancelar:')) {
    payload.turno_id = text.split(':')[1];
  }
} else if (textLower.startsWith('/reprogramar') || textLower === 'reprogramar' || textLower.includes('cambiar turno') || textLower.includes('mover turno') || textLower.startsWith('reprogramar:')) {
  comando = 'reprogramar';
  if (textLower.startsWith('reprogramar:')) {
    payload.turno_id = text.split(':')[1];
  }
}

return [{
  json: {
    comando: comando,
    chat_id: chatId,
    callback_query_id: callbackQueryId,
    text: textRaw,
    payload: payload
  }
}];
